import os
from torch.utils.data import Dataset
from PIL import Image

class DomainDataset(Dataset):
    def __init__(self, data_dir, txt_file, transform=None, return_domain=False):
        self.data_dir = data_dir
        self.transform = transform
        self.return_domain = return_domain
        self.samples = []
        with open(txt_file) as f:
            for line in f:
                p = line.strip().split()
                if len(p)==2:
                    fpath = os.path.join(data_dir, 'images', p[0])
                    self.samples.append((fpath, int(p[1])))
    def __len__(self):
        return len(self.samples)
    def __getitem__(self, idx):
        path, label = self.samples[idx]
        img = Image.open(path).convert('RGB')
        if self.transform:
            img = self.transform(img)
        if self.return_domain:
            rel = os.path.relpath(path, os.path.join(self.data_dir, 'images'))
            dom_str = rel.split(os.sep)[0]
            m = {'clipart':0,'infograph':1,'painting':2,'real':3,'sketch':4}
            return img, label, m.get(dom_str,-1)
        return img, label
